import itertools
import numpy as np
import pandas as pd
from sklearn.base import BaseEstimator, TransformerMixin
from sklearn.compose import ColumnTransformer
from sklearn.impute import SimpleImputer
from sklearn.linear_model import LogisticRegression
from sklearn.metrics import f1_score
from sklearn.model_selection import StratifiedKFold, cross_val_predict
from sklearn.pipeline import Pipeline
from sklearn.preprocessing import OneHotEncoder, StandardScaler

DATA='/Users/jiaruixu/work_space/agentic-learn/data/synth_clf.csv'

def best_f1_from_proba(y,p):
    best=(0,None)
    for t in np.unique(p):
        f=f1_score(y,(p>=t).astype(int))
        if f>best[0]:
            best=(f,t)
    return best

class FE(BaseEstimator, TransformerMixin):
    def __init__(self, add_bins=False, add_cross_bins=False, add_ratio_bins=False, drop_quadratic=False):
        self.add_bins=add_bins
        self.add_cross_bins=add_cross_bins
        self.add_ratio_bins=add_ratio_bins
        self.drop_quadratic=drop_quadratic

    def fit(self,X,y=None):
        self.noise_cols_=[c for c in X.columns if 'noise' in c.lower()]
        return self

    def transform(self,X):
        X=X.copy().drop(columns=self.noise_cols_,errors='ignore')

        for col in ['income','age','hours_worked','distance_km','satisfaction']:
            if col in X.columns:
                X[f'{col}_missing']=X[col].isna().astype(float)

        if 'income' in X.columns:
            X['log_income']=np.log1p(np.clip(X['income'],0,None))
            if not self.drop_quadratic:
                X['income_sq']=X['income']**2

        if 'age' in X.columns:
            X['age_centered']=X['age']-45
            if not self.drop_quadratic:
                X['age_centered_sq']=(X['age']-45)**2

        if 'hours_worked' in X.columns:
            X['log_hours']=np.log1p(np.clip(X['hours_worked'],0,None))
            if not self.drop_quadratic:
                X['hours_sq']=X['hours_worked']**2

        if 'distance_km' in X.columns:
            d=np.clip(X['distance_km'],0,None)
            X['log_distance']=np.log1p(d)
            X['distance_inv']=1.0/(1.0+d)
            if not self.drop_quadratic:
                X['distance_sq']=X['distance_km']**2

        if {'hours_worked','distance_km'}.issubset(X.columns):
            X['hours_div_distance']=X['hours_worked']/(1.0+X['distance_km'])
            X['hours_x_distance']=X['hours_worked']*X['distance_km']

        if 'satisfaction' in X.columns:
            X['satisfaction_gt3']=(X['satisfaction']>3).astype(float)
            X['satisfaction_centered']=X['satisfaction']-3.0

        if {'age','satisfaction'}.issubset(X.columns):
            X['age_x_satisfaction']=X['age']*X['satisfaction']

        if {'income','education'}.issubset(X.columns):
            m={'high_school':1.0,'bachelors':2.0,'masters':3.0,'phd':4.0}
            e=X['education'].map(m).astype(float)
            X['edu_ord']=e
            X['income_x_education']=X['income']*e

        if {'region','education'}.issubset(X.columns):
            X['region_education']=X['region'].astype(str)+'__'+X['education'].astype(str)

        if {'region','hours_worked'}.issubset(X.columns):
            b=pd.cut(X['hours_worked'],bins=[-np.inf,30,40,50,np.inf],labels=['lt30','30_40','40_50','gt50']).astype(str)
            X['region_hours_bucket']=X['region'].astype(str)+'__'+b

        if self.add_bins:
            if 'distance_km' in X.columns:
                X['distance_bucket']=pd.cut(X['distance_km'],bins=[-np.inf,2,5,10,20,40,np.inf],labels=['d0_2','d2_5','d5_10','d10_20','d20_40','d40p']).astype(str)
            if 'age' in X.columns:
                X['age_bucket']=pd.cut(X['age'],bins=[-np.inf,25,35,45,55,65,np.inf],labels=['a0_25','a25_35','a35_45','a45_55','a55_65','a65p']).astype(str)
            if 'income' in X.columns:
                X['income_bucket']=pd.cut(X['income'],bins=[-np.inf,15,25,40,60,np.inf],labels=['i0_15','i15_25','i25_40','i40_60','i60p']).astype(str)

        if self.add_cross_bins and self.add_bins:
            if {'education','distance_bucket'}.issubset(X.columns):
                X['education_distance_bucket']=X['education'].astype(str)+'__'+X['distance_bucket'].astype(str)
            if {'region','age_bucket'}.issubset(X.columns):
                X['region_age_bucket']=X['region'].astype(str)+'__'+X['age_bucket'].astype(str)
            if {'region','income_bucket'}.issubset(X.columns):
                X['region_income_bucket']=X['region'].astype(str)+'__'+X['income_bucket'].astype(str)

        if self.add_ratio_bins:
            if 'hours_div_distance' in X.columns:
                X['hours_div_distance_bucket']=pd.cut(X['hours_div_distance'],bins=[-np.inf,1,2,4,8,np.inf],labels=['r0_1','r1_2','r2_4','r4_8','r8p']).astype(str)
            if {'education','hours_div_distance_bucket'}.issubset(X.columns):
                X['education_ratio_bucket']=X['education'].astype(str)+'__'+X['hours_div_distance_bucket'].astype(str)

        return X


df=pd.read_csv(DATA)
X=df.drop(columns=['target'])
y=df['target'].astype(int)
cv=StratifiedKFold(n_splits=5,shuffle=True,random_state=42)

configs=[]
for add_bins,add_cross_bins,add_ratio_bins,drop_quad in itertools.product([False,True],[False,True],[False,True],[False,True]):
    if add_cross_bins and not add_bins:
        continue
    configs.append((add_bins,add_cross_bins,add_ratio_bins,drop_quad))

best=None
for cfg in configs:
    add_bins,add_cross_bins,add_ratio_bins,drop_quad=cfg
    fe=FE(add_bins=add_bins,add_cross_bins=add_cross_bins,add_ratio_bins=add_ratio_bins,drop_quadratic=drop_quad)
    Xt=fe.fit_transform(X)
    num=Xt.select_dtypes(include=[np.number]).columns.tolist()
    cat=Xt.select_dtypes(exclude=[np.number]).columns.tolist()

    pipe=Pipeline([
        ('fe',fe),
        ('pre',ColumnTransformer([
            ('num',Pipeline([('imp',SimpleImputer(strategy='median')),('sc',StandardScaler())]),num),
            ('cat',Pipeline([('imp',SimpleImputer(strategy='most_frequent')),('ohe',OneHotEncoder(handle_unknown='ignore'))]),cat),
        ])),
        ('clf',LogisticRegression(penalty='l2',C=2.0,solver='lbfgs',max_iter=10000,random_state=42))
    ])

    p=cross_val_predict(pipe,X,y,cv=cv,method='predict_proba',n_jobs=1)[:,1]
    f1,t=best_f1_from_proba(y,p)
    print(cfg,'->',round(f1,6),'thr',round(float(t),6))
    if best is None or f1>best[0]:
        best=(f1,cfg,t)

print('BEST',best)
